<?php
namespace App\Domain\Repayments\Actions;
use App\Domain\Accounting\Services\AutoPoster;use App\Enums\InstallmentStatus;use App\Enums\LoanStatus;use App\Enums\RepaymentStatus;use App\Models\Loan;use App\Models\LoanRepayment;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\DB;use Illuminate\Support\Str;use Illuminate\Validation\ValidationException;
class RecordLoanRepayment{public function __construct(private AutoPoster $accounting){}public function execute(Loan $loan,array $data):LoanRepayment{if($existing=LoanRepayment::query()->where('idempotency_key',$data['idempotency_key'])->first())return $existing->load('allocations');return DB::transaction(function()use($loan,$data){$loan=Loan::query()->lockForUpdate()->findOrFail($loan->id);if(!in_array($loan->status,[LoanStatus::Active,LoanStatus::InArrears,LoanStatus::Restructured],true))throw ValidationException::withMessages(['loan'=>['This loan is not open for repayment.']]);$repayment=LoanRepayment::query()->create(['loan_id'=>$loan->id,'member_id'=>$loan->member_id,'reference'=>'RPT-'.strtoupper(Str::ulid()),'idempotency_key'=>$data['idempotency_key'],'channel'=>$data['channel'],'currency'=>$data['currency']??'NGN','amount_minor'=>$data['amount_minor'],'status'=>RepaymentStatus::Successful,'external_reference'=>$data['external_reference']??null,'received_at'=>$data['received_at']??now(),'recorded_by'=>Auth::id(),'notes'=>$data['notes']??null]);$remaining=(int)$data['amount_minor'];$installments=$loan->installments()->whereNotIn('status',[InstallmentStatus::Paid->value,InstallmentStatus::Waived->value,InstallmentStatus::Rescheduled->value])->orderBy('due_date')->lockForUpdate()->get();foreach($installments as $installment){foreach(['recovery_expenses'=>['recovery_expenses_due_minor','recovery_expenses_paid_minor'],'penalties'=>['penalties_due_minor','penalties_paid_minor'],'charges'=>['charges_due_minor','charges_paid_minor'],'interest'=>['interest_due_minor','interest_paid_minor'],'principal'=>['principal_due_minor','principal_paid_minor']] as $component=>$columns){if($remaining<=0)break;[$due,$paid]=$columns;$outstanding=$installment->{$due}-$installment->{$paid};if($outstanding<=0)continue;$amount=min($remaining,$outstanding);$installment->{$paid}+=$amount;$installment->amount_paid_minor+=$amount;$installment->save();$repayment->allocations()->create(['loan_repayment_installment_id'=>$installment->id,'component'=>$component,'amount_minor'=>$amount]);$remaining-=$amount;}$totalDue=$installment->principal_due_minor+$installment->interest_due_minor+$installment->charges_due_minor+$installment->penalties_due_minor+$installment->recovery_expenses_due_minor;$status=$installment->amount_paid_minor>=$totalDue?InstallmentStatus::Paid:($installment->due_date->isPast()?InstallmentStatus::Overdue:InstallmentStatus::PartiallyPaid);$installment->update(['status'=>$status]);if($remaining<=0)break;}$allocated=$data['amount_minor']-$remaining;$newOutstanding=max(0,$loan->outstanding_minor-$allocated);$hasOverdue=$loan->installments()->where('status',InstallmentStatus::Overdue->value)->exists();$loan->update(['outstanding_minor'=>$newOutstanding,'status'=>$newOutstanding<=0?LoanStatus::Settled:($hasOverdue?LoanStatus::InArrears:LoanStatus::Active)]);$repayment->update(['allocated_minor'=>$allocated,'unallocated_minor'=>$remaining]);$repayment->load('allocations');$context=['member_id'=>$loan->member_id,'loan_id'=>$loan->id,'entry_date'=>$repayment->received_at->toDateString(),'currency'=>$repayment->currency];foreach($repayment->allocations->groupBy('component') as $component=>$rows)$this->accounting->postIfConfigured('repayment.'.$component,$repayment,(int)$rows->sum('amount_minor'),$context);return $repayment->refresh()->load('allocations');});}}
